df_ma = df_complete[df_complete['StateofOriginCleaned'] == 'Massachusetts'].copy()

# Helper to count unique samples
count_col = 'id' if 'id' in df_ma.columns else None
def n_samples(frame):
    return frame['id'].nunique() if count_col else len(frame)

# Count samples per group
samples_per_group = df_ma.groupby('groupid')['id'].nunique().reset_index()
samples_per_group.columns = ['Group ID', 'Sample Count']

# For each group, collect all unique adulterants
adulterants_per_group = {}
for group_id in df_ma['groupid'].unique():
    df_group = df_ma[df_ma['groupid'] == group_id]
    all_adulterants = set()

    for _, row in df_group.iterrows():
        active_cuts = str(row.get('ActiveCuts') or '')
        if active_cuts and active_cuts.lower() != 'nan':
            cuts = [c.strip() for c in active_cuts.split(',')]
            for cut in cuts:
                if cut and cut.lower() != 'none detected':
                    all_adulterants.add(cut)

    adulterants_per_group[group_id] = '; '.join(sorted(all_adulterants)) if all_adulterants else 'None Detected'

# Add adulterants column
samples_per_group['Adulterants Found'] = samples_per_group['Group ID'].map(adulterants_per_group)

