    'Group ID': ['TOTAL'],
    'Sample Count': [total_samples],
    'Adulterants Found': ['See individual groups above']
})

samples_per_group = pd.concat([samples_per_group, sum_row], ignore_index=True)

# Build table output
table_rows = []
for _, row in samples_per_group.iterrows():
    table_rows.append([
        str(row['Group ID']),
