result = {
    "answer": f"Massachusetts has {total_groups} collection groups with a total of {total_samples} Complete samples. The table below shows the sample count per group and the unique adulterants detected in each group's samples.",
    "metrics": [
        {"label": "Total Samples (MA)", "value": total_samples},
        {"label": "Collection Groups", "value": total_groups},
        {"label": "Unique Adulterants Detected", "value": len(set([a for a in adulterants_per_group.values() if a != 'None Detected']))}
