import json
import pandas as pd
import numpy as np

# Filter to Complete status, Massachusetts, and 2025
df_complete = df[df['status'] == 'Complete'].copy()

# Ensure acquired_date is datetime
df_complete['acquired_date'] = pd.to_datetime(df_complete['acquired_date'], errors='coerce')

# Filter for Massachusetts and year 2025
df_ma = df_complete[
    (df_complete['StateofOriginCleaned'] == 'Massachusetts') &
    (df_complete['acquired_date'].dt.year == 2025)
].copy()

# Filter for samples that contain both fentanyl AND xylazine in AllIllicits
df_both = df_ma[
    df_ma['AllIllicits'].fillna('').str.contains('fentanyl', case=False, na=False) &
    df_ma['AllIllicits'].fillna('').str.contains('xylazine', case=False, na=False)
].copy()

# Count by town
town_counts = df_both['TownofOriginCleaned'].value_counts()

if len(town_counts) == 0:
    result = {
        "answer": "No samples in Massachusetts in 2025 contained both fentanyl and xylazine.",
        "detail": "Filtered to Complete status, StateofOriginCleaned=='Massachusetts', year 2025, AllIllicits containing both 'fentanyl' and 'xylazine'."
    }
else:
    top_town = town_counts.index[0]
    top_count = int(town_counts.iloc[0])

    result = {
        "answer": f"{top_town}, Massachusetts had the highest count of fentanyl cut with xylazine in 2025, with {top_count} sample(s).",
        "metrics": [
            {"label": "Top Town", "value": top_town},
            {"label": "Sample Count", "value": top_count},
            {"label": "Total MA Samples (Fent+Xyl)", "value": int(len(df_both))}
        ],
        "list": {
            "items": [
                {"label": town, "value": str(int(count))}
                for town, count in town_counts.head(10).items()
            ]
        },
        "detail": "Filtered to Complete status, Massachusetts samples from 2025 where AllIllicits contains both 'fentanyl' and 'xylazine'."
    }

print(json.dumps(result, default=str))
